import React from "react";
import { Link } from "react-router-dom";
import PropTypes from "prop-types";
import useScrollTrigger from "@material-ui/core/useScrollTrigger";
import Slide from "@material-ui/core/Slide";
import AppBar from "@material-ui/core/AppBar";
import Toolbar from "@material-ui/core/Toolbar";
import Button from "@material-ui/core/Button";
import Box from "@material-ui/core/Box";
import Container from "@material-ui/core/Container";

function HideOnScroll(props) {
  const { children, window } = props;
  const trigger = useScrollTrigger({ target: window ? window() : undefined });

  return (
    <Slide appear={false} direction="down" in={!trigger}>
      {children}
    </Slide>
  );
}

HideOnScroll.propTypes = {
  children: PropTypes.element.isRequired,
  window: PropTypes.func
};

class LgNavbar extends React.Component {
  render(props) {
    return (
      <div>
        <Box component="div" display={{ xs: "none", sm: "block", md: "block" }}>
          <HideOnScroll {...props}>
            <AppBar color="primary" shadow="none">
              <Container
                maxWidth="md"
                style={{
                  paddingLeft: 0,
                  paddingRight: 0
                }}
              >
                <Toolbar>
                  <Box flexGrow={1}>

                    <Link style={{textDecoration:"none"}} to="/">
                      <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>Febarrientos</Button>
                    </Link>
                  </Box>
                  <Box>
                    {/* <Link to="/work">Work</Link>
                    <Link to="/projects">Projects</Link>
                    <Link to="/about">About</Link> */}
                    <Link style={{textDecoration:"none"}} to="/work">
                      <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>Work</Button>
                    </Link>
                    <Link style={{textDecoration:"none"}} to="/projects">
                      <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>Projects</Button>
                    </Link>
                    <Link style={{textDecoration:"none"}} to="/about">
                      <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>About</Button>
                    </Link>
                  </Box>
                </Toolbar>
              </Container>
            </AppBar>
          </HideOnScroll>
        </Box>
      </div>
    );
  }
}

export default LgNavbar;
