import React from "react";
import PropTypes from "prop-types";
import { Link } from "react-router-dom";

import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import Dialog from "@material-ui/core/Dialog";
import IconButton from "@material-ui/core/IconButton";
import MenuIcon from "@material-ui/icons/Menu";
import Button from "@material-ui/core/Button";

function SimpleDialog(props) {
  // const classes = useStyles();
  const { onClose, selectedValue, open } = props;

  const handleClose = () => {
    onClose(selectedValue);
  };

  const handleListItemClick = value => {
    onClose(value);
  };

  return (
    <Dialog
      onClose={handleClose}
      aria-labelledby="simple-dialog-title"
      open={open}
    >
      {/* <DialogTitle id="simple-dialog-title">Set backup account</DialogTitle> */}
      <List>
        <ListItem style={{textDecoration:"none"}} onClick={() => handleListItemClick()}>
          <Link to="/work">
            <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>Work</Button>
          </Link>
        </ListItem>
        <ListItem style={{textDecoration:"none"}} onClick={() => handleListItemClick()}>
          <Link to="/projects">
            <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>Projects</Button>
          </Link>
        </ListItem>
        <ListItem onClick={() => handleListItemClick()}>
          <Link style={{textDecoration:"none"}} to="/about">
            <Button color="secondary" disableRipple style={{ backgroundColor: "transparent" }}>About</Button>
          </Link>
        </ListItem>
      </List>
    </Dialog>
  );
}

SimpleDialog.propTypes = {
  onClose: PropTypes.func.isRequired,
  open: PropTypes.bool.isRequired,
  selectedValue: PropTypes.string.isRequired
};

export default function SimpleDialogDemo() {
  const [open, setOpen] = React.useState(false);

  const handleClickOpen = () => {
    setOpen(true);
  };

  const handleClose = value => {
    setOpen(false);
  };

  return (
    <div>
      <IconButton
        onClick={handleClickOpen}
        edge="start"
        disableRipple 
        style={{ backgroundColor: "#fff" }}
        color="secondary"
        aria-label="menu"
      >
        <MenuIcon />
      </IconButton>
      <SimpleDialog open={open} onClose={handleClose} />
    </div>
  );
}
